// 从Bellkeeper API响应中提取RSS源并构建URL
const response = $input.first().json;
const sources = response.data || response.items || response;

const results = [];
for (const source of sources) {
  let feedUrl = source.url;
  if (feedUrl.startsWith('/')) {
    feedUrl = 'http://rsshub:1200' + feedUrl;
  }

  const sourceTags = (source.tags || []).map(t => typeof t === 'object' ? (t.name || '') : String(t)).filter(t => t);
  if (source.category && !sourceTags.includes(source.category)) {
    sourceTags.push(source.category);
  }

  results.push({
    json: {
      id: source.id,
      name: source.name,
      feedUrl: feedUrl,
      originalUrl: source.url,
      category: source.category || '',
      tags: sourceTags,
      isActive: source.is_active
    }
  });
}

return results;

// 将所有Feed响应与RSS源信息按索引配对，解析所有文章
const feeds = $input.all();
const sources = $('提取RSS源').all();

function extractTag(content, tag) {
  const cdataRegex = new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>`, 'i');
  const plainRegex = new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i');
  const hrefRegex = new RegExp(`<${tag}[^>]*href=["']([^"']+)["']`, 'i');
  let match = content.match(cdataRegex);
  if (match) return match[1].trim();
  match = content.match(plainRegex);
  if (match) return match[1].trim();
  if (tag === 'link') {
    match = content.match(hrefRegex);
    if (match) return match[1].trim();
  }
  return '';
}

const allArticles = [];

for (let i = 0; i < feeds.length; i++) {
  const feedData = feeds[i].json;
  const source = sources[i] ? sources[i].json : {};
  const xml = feedData.data || feedData.body || '';

  if (!xml || typeof xml !== 'string') continue;

  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  const entryRegex = /<entry[^>]*>([\s\S]*?)<\/entry>/gi;
  const regex = xml.includes('<entry') ? entryRegex : itemRegex;

  let matches;
  while ((matches = regex.exec(xml)) !== null) {
    const itemXml = matches[1];
    const title = extractTag(itemXml, 'title');
    const link = extractTag(itemXml, 'link');
    if (title && link) {
      allArticles.push({
        json: {
          url: link,
          title: title,
          tags: source.tags || [],
          category: source.category || '',
          sourceName: source.name || ''
        }
      });
    }
  }
}

if (allArticles.length === 0) {
  return [{ json: { _noArticles: true, _sourceCount: sources.length } }];
}

return allArticles;

const now = new Date();
const hour = now.getHours();
let period = '早间';
if (hour >= 11 && hour < 15) period = '午间';
else if (hour >= 17) period = '晚间';

let sourceCount = 0;
try { sourceCount = $('提取RSS源').all().length; } catch(e) {}

// Get article results from "推送文章到Ingest"
const articleResults = $('推送文章到Ingest').all();
let total = articleResults.length;
let success = 0;
let duplicate = 0;
let failed = 0;
for (const r of articleResults) {
  const d = r.json;
  if (d.error) {
    failed++;
  } else if (d.success === false && d.status === 'duplicate') {
    duplicate++;
  } else if (d.success === true) {
    success++;
  } else {
    success++;
  }
}

// Get parsing results
let parseSuccess = 0;
let parseFailed = 0;
let parseTotal = 0;
try {
  const parseResults = $('批量解析文档').all();
  const groupResults = $('按Dataset分组').all();

  for (const r of parseResults) {
    const d = r.json;
    // Find corresponding group to get document count
    const group = groupResults.find(g => g.json.dataset_id === d.dataset_id);
    const docCount = group ? group.json.document_ids.length : 0;
    parseTotal += docCount;

    if (d.error || (d.code && d.code !== 0)) {
      parseFailed += docCount;
    } else {
      parseSuccess += docCount;
    }
  }
} catch(e) {
  // No parsing results, skip
}

const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
const timeStr = `${String(hour).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;

let summary = `📰 ${period}RSS定时采集已完成\n⏰ ${dateStr} ${timeStr}\n📊 RSS源: ${sourceCount} 个 | 文章: ${total} 篇`;
summary += `\n✅ 入库: ${success} | ⏩ 已存在: ${duplicate} | ❌ 失败: ${failed}`;

if (parseTotal > 0) {
  summary += `\n🔄 解析: ${parseSuccess}/${parseTotal} 成功`;
  if (parseFailed > 0) {
    summary += ` | ⚠️ ${parseFailed} 失败`;
  }
}

return [{ json: { summary, timestamp: now.toISOString() } }];

// 无文章时也发送通知
const now = new Date();
const hour = now.getHours();
let period = '早间';
if (hour >= 11 && hour < 15) period = '午间';
else if (hour >= 17) period = '晚间';

let sourceCount = 0;
try { sourceCount = $('提取RSS源').all().length; } catch(e) {}

const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
const timeStr = `${String(hour).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;

const summary = `📰 ${period}RSS定时采集已完成\n⏰ ${dateStr} ${timeStr}\n📊 RSS源: ${sourceCount} 个 | 文章: 0 篇 (无新内容)`;

return [{ json: { summary, timestamp: now.toISOString() } }];

// Extract document IDs from successful upload responses
const results = $input.all();
const documents = [];

for (const item of results) {
  const d = item.json;

  // Only process successful uploads
  if (d.success === true && d.uploadResult) {
    // uploadResult = { data: { code, message, data: [...] }, dataset_id }
    const ragflowResp = d.uploadResult.data;
    const datasetId = d.uploadResult.dataset_id;

    if (!ragflowResp || !datasetId) continue;

    // RAGFlow response is wrapped: { code: 0, data: [{id: ...}] }
    // The actual document list is in ragflowResp.data
    const docData = ragflowResp.data || ragflowResp;

    let docId = null;

    if (Array.isArray(docData) && docData.length > 0 && docData[0].id) {
      docId = docData[0].id;
    } else if (typeof docData === 'object' && docData.id) {
      docId = docData.id;
    }

    if (docId) {
      documents.push({
        document_id: docId,
        dataset_id: datasetId,
        title: d.title || 'Untitled',
        url: d.url || ''
      });
    }
  }
}

return [{ json: { documents, count: documents.length } }];

// Group document IDs by dataset_id
const input = $input.first().json;
const documents = input.documents || [];

const grouped = {};
for (const doc of documents) {
  const datasetId = doc.dataset_id;
  if (!grouped[datasetId]) {
    grouped[datasetId] = {
      dataset_id: datasetId,
      document_ids: [],
      titles: []
    };
  }
  grouped[datasetId].document_ids.push(doc.document_id);
  grouped[datasetId].titles.push(doc.title);
}

// Convert to array for iteration
const result = Object.values(grouped);
return result.map(g => ({ json: g }));
